function GetFrequency(byte1, byte2) {
    var value1 = byte1.toString(2)
    while(value1.length<8){
    value1='0'+value1;}
    var value2 = byte2.toString(2);
    while(value2.length<8){
    value2='0'+value2;}
    var value = value1 + value2;

    return parseInt(value,2)/1000;
}

function GetVoltageValue(byte1, byte2) {
    var value1 = byte1.toString(2)
    while(value1.length<8){
    value1='0'+value1;}
    var value2 = byte2.toString(2);
    while(value2.length<8){
    value2='0'+value2;}
    var value = value1[2]+value1[3]+value1[4]+value1[5]+value1[6]+value1[7] + value2;

    return parseInt(value,2)/10;
}

function GetCurrentValue(byte1, byte2) {
    var value1 = byte1.toString(2)
    while(value1.length<8){
    value1='0'+value1;}
    var value2 = byte2.toString(2);
    while(value2.length<8){
    value2='0'+value2;}
    var value = value1[3]+value1[4]+value1[5]+value1[6]+value1[7] + value2;
    if(parseInt(value1[2],2) == 0)
        return parseInt(value,2)/100;
    else
        return parseInt(value,2)/10;
}

function GetPhase(mainByte)
{
    var phase = mainByte.toString(2);
    while(phase.length<8){
    phase='0'+phase;}
    phase=phase[0].toString(2)+phase[1].toString(2);
    return parseInt(phase,2);
}

function GetEnergy(mainByte)
{
    var phase = mainByte.toString(2);
    while(phase.length<8){
    phase='0'+phase;}
    phase=phase[0].toString(2);
    return parseInt(phase,2);
}

function GetPhasePower(mainByte)
{
    var phase = mainByte.toString(2);
    while(phase.length<8){
    phase='0'+phase;}
    phase=phase[2].toString(2)+phase[3].toString(2);
    return parseInt(phase,2);
}

function GetTariff(mainByte)
{
    var tariff = mainByte.toString(2);
    while(tariff.length<8){
    tariff='0'+tariff;}
    tariff=tariff[1].toString(2)+tariff[2].toString(2)+tariff[3].toString(2)+tariff[4].toString(2);
    return parseInt(tariff,2);
}

